/**
 * Reserve a fresh entity id without registering it with any queries or adding
 * traits. Used by the deferred command buffer so that a spawned entity has a
 * stable, alive id that can be referenced before the buffer is flushed.
 */
export function reserveEntity(world: World): Entity {
    const ctx = world[$internal];
    const entity = allocateEntity(ctx.entityIndex);
    ctx.entityTraits.set(entity, new Set());
    return entity;
