/**
 * A deferred command buffer batches entity mutations so they can be applied in
 * a single pass. This lets callers safely mutate entities while iterating a
 * query (e.g. inside `updateEach`) without disturbing the iteration.
 *
 * Commands are queued in order and executed on the next trigger:
 *  - the end of an `updateEach` callback,
 *  - an explicit `flush()`,
 *  - a non-deferred mutation on an entity that has pending commands.
 *
 * While commands are buffered, `entity.has` and `entity.get` report the state
 * the entity *would* have after the buffer is flushed.
 */
export interface DeferredCommands {
    /** Queue an entity spawn. Returns the reserved entity immediately. */
    spawn(...traits: ConfigurableTrait[]): Entity;
    /** Queue an entity destruction. */
    destroy(entity: Entity): void;
    /** Queue traits (or relation pairs) to be added to an entity. */
    add(entity: Entity, ...traits: ConfigurableTrait[]): void;
    /** Queue traits (or relation pairs) to be removed from an entity. */
    remove(entity: Entity, ...traits: (Trait | RelationPair)[]): void;
    /**
     * Queue an exclusive relation. Existing pairs for the relation are replaced
     * by the given pair. A wildcard `'*'` target clears all pairs.
     */
    addExclusive(entity: Entity, ...pairs: RelationPair[]): void;
    /** Execute the currently buffered commands. */
    flush(): void;
}

const REMOVE = Symbol('remove');

type TraitOp = { remove: boolean; value?: any };
type TargetOp = { remove: boolean; params?: Record<string, unknown> };
type RelOp = {
    /** Exclusive replace: the entity should end with exactly `targets`. */
    replace: boolean;
    targets: Map<Entity, TargetOp>;
    /** Wildcard removal: drop every existing target for the relation. */
    clearAll: boolean;
};

type EntityPlan = {
    spawnedHere: boolean;
    destroyed: boolean;
    initialTraits: ConfigurableTrait[];
    traitOps: Map<Trait, TraitOp>;
    relOps: Map<Relation<Trait>, RelOp>;
};

type Command =
    | { kind: 'spawn'; entity: Entity; traits: ConfigurableTrait[] }
    | { kind: 'destroy'; entity: Entity }
    | { kind: 'add'; entity: Entity; configs: ConfigurableTrait[] }
    | { kind: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
    | { kind: 'addExclusive'; entity: Entity; pairs: RelationPair[] };

type Scope = {
    commands: Command[];
    /** Entities reserved by a spawn command in this scope. */
    reserved: Set<Entity>;
};

function createScope(): Scope {
    return { commands: [], reserved: new Set() };
}

function newPlan(): EntityPlan {
    return {
        spawnedHere: false,
        destroyed: false,
        initialTraits: [],
        traitOps: new Map(),
        relOps: new Map(),
    };
}

function getRelOp(plan: EntityPlan, relation: Relation<Trait>): RelOp {
    let op = plan.relOps.get(relation);
    if (!op) {
        op = { replace: false, targets: new Map(), clearAll: false };
        plan.relOps.set(relation, op);
    }
    return op;
