            op.clearAll = true;
            op.targets.clear();
        } else if (typeof target === 'number') {
            op.targets.set(target, { remove: true });
        }
        return;
    }
    plan.traitOps.set(trait, { remove: true });
}

function applyExclusivePair(plan: EntityPlan, pair: RelationPair) {
    const pairCtx = pair[$internal];
    const relation = pairCtx.relation as Relation<Trait>;
    const target = pairCtx.target;
