import { createWorld, relation, trait, universe } from '../src';

const Position = trait({ x: 0, y: 0 });
const Velocity = trait({ x: 0, y: 0 });
const Health = trait({ value: 100 });
const IsActive = trait();

describe('Deferred command buffer', () => {
    beforeEach(() => {
        universe.reset();
    });

    it('exposes the deferred API on the world', () => {
        const world = createWorld();
        expect(typeof world.deferred.spawn).toBe('function');
        expect(typeof world.deferred.destroy).toBe('function');
        expect(typeof world.deferred.add).toBe('function');
        expect(typeof world.deferred.remove).toBe('function');
        expect(typeof world.deferred.addExclusive).toBe('function');
        expect(typeof world.deferred.flush).toBe('function');
    });

    it('defers spawn until flush', () => {
        const world = createWorld();
        const before = world.query(Position).length;

        const entity = world.deferred.spawn(Position({ x: 1, y: 2 }));

        // Not yet visible to queries.
        expect(world.query(Position).length).toBe(before);

        world.deferred.flush();

        expect(world.query(Position).length).toBe(before + 1);
        expect(entity.get(Position)).toEqual({ x: 1, y: 2 });
    });

    it('defers add and remove until flush', () => {
        const world = createWorld();
        const entity = world.spawn(Position);

        world.deferred.add(entity, Velocity({ x: 5, y: 5 }));
